import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2020年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2020年/核心总结.md","filePath":"01_letters/2020年/核心总结.md"}'),r={name:"01_letters/2020年/核心总结.md"};function o(u,l,h,n,d,s){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2020年巴菲特致股东信核心总结" tabindex="-1">2020年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2020年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2020年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>GAAP净利润425亿美元，但包含267亿美元未实现投资收益和110亿美元资产减值</li><li>营业利润219亿美元，下降9%</li><li>每股市场价值增长2.4%，大幅落后于标普500的18.4%</li><li>通过回购提升每股内在价值（回购5%股份）</li></ul><h2 id="四大珍宝资产" tabindex="-1">四大珍宝资产 <a class="header-anchor" href="#四大珍宝资产" aria-label="Permalink to &quot;四大珍宝资产&quot;">​</a></h2><p>巴菲特首次明确列出伯克希尔的四大核心资产：</p><h3 id="_1-保险业务" tabindex="-1">1. 保险业务 <a class="header-anchor" href="#_1-保险业务" aria-label="Permalink to &quot;1. 保险业务&quot;">​</a></h3><ul><li>浮存金1380亿美元，创历史新高</li><li>无成本甚至负成本的融资来源</li><li>可投资股票而非仅债券（竞争对手受监管限制）</li><li>Ajit Jain管理的独特优势</li></ul><h3 id="_2-bnsf铁路-100-控股" tabindex="-1">2. BNSF铁路（100%控股） <a class="header-anchor" href="#_2-bnsf铁路-100-控股" aria-label="Permalink to &quot;2. BNSF铁路（100%控股）&quot;">​</a></h3><ul><li>美国最大铁路公司，承运15%的非本地货运</li><li>自2010年收购以来投资410亿美元</li><li>累计分红418亿美元给伯克希尔</li><li>2020年利润率提升2.9个百分点（货运量下降7%）</li></ul><h3 id="_3-苹果-5-4-股权" tabindex="-1">3. 苹果（5.4%股权） <a class="header-anchor" href="#_3-苹果-5-4-股权" aria-label="Permalink to &quot;3. 苹果（5.4%股权）&quot;">​</a></h3><ul><li>持股市值1204亿美元，成本311亿美元</li><li>回购的魔力：虽减持但仍持有5.4%（因苹果回购）</li><li>伯克希尔回购让股东间接增加苹果持股10%</li><li>年均股息7.75亿美元</li></ul><h3 id="_4-伯克希尔能源-91-控股" tabindex="-1">4. 伯克希尔能源（91%控股） <a class="header-anchor" href="#_4-伯克希尔能源-91-控股" aria-label="Permalink to &quot;4. 伯克希尔能源（91%控股）&quot;">​</a></h3><ul><li>21年间收益从1.22亿增至34亿美元</li><li>从不分红，全部留存再投资</li><li>180亿美元西部电网改造项目（2006-2030年）</li><li>清洁能源领导者</li></ul><h2 id="美国企业精神-双城记" tabindex="-1">美国企业精神（双城记） <a class="header-anchor" href="#美国企业精神-双城记" aria-label="Permalink to &quot;美国企业精神（双城记）&quot;">​</a></h2><ul><li><p><strong>奥马哈</strong>：National Indemnity、NFM等成功故事</p><ul><li>NFM：B女士1915年俄罗斯移民，1936年创办家具店</li><li>1946年净资产仅7.2万美元，现金50美元</li><li>1983年被伯克希尔收购，现全美最大三家家居店</li></ul></li><li><p><strong>诺克斯维尔</strong>：Clayton Homes和Pilot Travel Centers</p><ul><li>两家公司合计雇佣4.7万人</li><li>年税前利润均超10亿美元</li><li>创业者从微小资本起步的成功典范</li></ul></li></ul><h2 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h2><ul><li>年末市值2810亿美元</li><li>新增持仓：雪佛龙、默克、艾伯维、威瑞森等</li><li>清仓航空股（因疫情）</li><li>比亚迪持股市值59亿美元（成本仅2.32亿美元）</li></ul><h2 id="回购的力量" tabindex="-1">回购的力量 <a class="header-anchor" href="#回购的力量" aria-label="Permalink to &quot;回购的力量&quot;">​</a></h2><ul><li>2020年回购247亿美元（约5%股份）</li><li>不在任意价格回购，坚持价值原则</li><li>回购增加留存股东的每股内在价值</li><li>与被投资公司回购形成双重增益</li></ul><h2 id="美国信念" tabindex="-1">美国信念 <a class="header-anchor" href="#美国信念" aria-label="Permalink to &quot;美国信念&quot;">​</a></h2><ul><li>&quot;永远不要押注美国&quot;</li><li>232年历史中充分释放人类潜能</li><li>宪法&quot;建立更完美联邦&quot;的理想仍在推进</li><li>创业者如Carnegie、Rockefeller、B女士等成就美国奇迹</li></ul><h2 id="伯克希尔合伙人文化" tabindex="-1">伯克希尔合伙人文化 <a class="header-anchor" href="#伯克希尔合伙人文化" aria-label="Permalink to &quot;伯克希尔合伙人文化&quot;">​</a></h2><ul><li>始于1956年巴菲特合伙企业</li><li>&quot;尽管形式是公司，态度是合伙人&quot;</li><li>四个&quot;桶&quot;的股东结构： <ul><li>创始人（巴菲特股份将逐步捐出）</li><li>指数基金（被动持有）</li><li>主动型机构（根据估值买卖）</li><li>个人投资者（最珍视的群体）</li></ul></li><li>不迎合华尔街分析师</li></ul><h2 id="疫情应对" tabindex="-1">疫情应对 <a class="header-anchor" href="#疫情应对" aria-label="Permalink to &quot;疫情应对&quot;">​</a></h2><ul><li>年度股东大会改为线上举行</li><li>Greg Abel与巴菲特在空旷竞技场面对摄像机</li><li>Yahoo直播，CNBC的Becky Quick远程提问</li><li>2021年将Charlie Munger请回舞台</li></ul><h2 id="固定资产规模" tabindex="-1">固定资产规模 <a class="header-anchor" href="#固定资产规模" aria-label="Permalink to &quot;固定资产规模&quot;">​</a></h2><ul><li>伯克希尔拥有美国最多的固定资产（1540亿美元）</li><li>超过AT&amp;T的1270亿美元</li><li>资产密集型业务（BNSF、BHE）需要大量资本支出</li><li>但仍能获得适当回报</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><ul><li>&quot;好东西太多可以……太棒了&quot;（梅·韦斯特）</li><li>商业不会因&quot;高难度动作&quot;加分</li><li>不要问理发师是否需要理发</li><li>信任与长期关系是伯克希尔的基石</li></ul><h2 id="接班人安排" tabindex="-1">接班人安排 <a class="header-anchor" href="#接班人安排" aria-label="Permalink to &quot;接班人安排&quot;">​</a></h2><ul><li>BNSF：Katie Farmer接任CEO（首位女性铁路CEO）</li><li>Greg Abel和Ajit Jain继续分管业务</li><li>股东大会Charlie Munger回归</li></ul>',31)])])}const _=i(r,[["render",o]]);export{q as __pageData,_ as default};
